struct node {
    int l, r, k, i;
};
void solve(int CASE)
{
    int n, m; cin >> n >> m;
    var a = vector<pii>(n + 1);
    fa(i, 1, n)cin >> a[i].px, a[i].py = i;
    var p = vector<node>(m + 1);
    fa(i, 1, m) {
        int l, r, x; cin >> l >> r >> x;
        p[i] = { l, r, x, i };
    }
    sort(all1(a));
    sort(all1(p), [](const node& a, const node& b)->bool {
        return a.k < b.k;
        });
    var t = FenwickTree<int>(n + 1);
    var ans = vector<int>(m + 1);
    int now = 1;
    fa(i, 1, m) {
        const var& [l, r, k, id] = p[i];
        while (now <= n and a[now].px <= k) {
            t.update(a[now].py, 1);
            now++;
        }
        ans[id] = t.query(l, r);
    }
    fa(i, 1, m)cout << ans[i] << endl;
    return;
}
